import React from 'react';
import { useLocation } from 'react-router-dom';
import './Footer.scss';
import { PropTypes } from 'prop-types';

export const Footer = ({ setItem }) => {
  // const history = useHistory();
  const app = document.querySelector('.App');
  const location = useLocation();
  const { pathname } = location;
  // const match = useRouteMatch();
  // const val = match.path;
  // const { } = history.location.pathname;
  // console.log(history);
  // console.log(location);
  // console.log(pathname);

  return (
    <footer className="Footer">
      {pathname.includes('/home') && (
        <a href="/#" className="Footer-Scroll" onClick={() => 
          app.style.
       setItem(true)}>Scroll to top&nbsp;</a>
      )}
      {pathname.includes('/articles') && (
      <a href="/articles" onClick={() => setItem(false)} className="Footer-ScrollArticles">&nbsp;</a>
      )}
      <p className="Footer-Copyright">
        <strong>News App</strong>
        &nbsp;News App 2021 copyright all rights reserved
      </p>
      <div className="Footer-Socials">
        <a href="http://insagram.com" className="Footer-Instagram socials">
          {}
        </a>
        <a href="http://twitter.com" className="Footer-Twitter socials">{}</a>
        <a href="http://linkedin.com" className="Footer-LinkedIn socials">{}</a>
      </div>
    </footer>
  );
};

Footer.propTypes = {
  setItem: PropTypes.func.isRequired,
};
